-- Toplam kullanıcı sayısı
SELECT COUNT(*) as total_users FROM users;

-- Toplam soru sayısı
SELECT COUNT(*) as total_questions FROM questions;

-- Toplam etap sayısı
SELECT COUNT(*) as total_stages FROM stages;

